function buildImportRulesV2(mode, myCoName) {
  return [
    mode === "member"
      ? "You import under " + (myCoName || "your own company") + ": the Company column is prefilled, its dropdown offers only your company, and any row naming another company is rejected. The same lock applies in Sync: you can only update your own company's activities."
      : "Set the Company column per row to load every contractor in one file. Companies, buildings, levels, zones, systems and crews that do not yet exist are created by the Admin importer.",
    "Required on every row when adding: Description, Building, System and Planned start; on a single-building project a blank Building fills itself. Milestone rows (Milestone = Yes) relax Building and System.",
    "Rows with no Description, System, Planned start and Code are ignored, so prefilled columns on unused rows are harmless.",
    "Dates are YYYY-MM-DD. Witness invite Yes needs Witness date & time as YYYY-MM-DD HH:MM. Witness columns store scheduling data only; invites are always sent from the witness flow.",
    "Discipline, Crews and Predecessors take semicolon-separated lists. Predecessors accept a Ref from this file (plain number) or an existing activity code written as #57.",
    "Constraints live on their own sheet, keyed by Activity ref; each import stamps them as raised by you in the constraint history.",
    "Leave the Code column empty when adding. To update existing activities, export the workbook, edit it and re-import in Sync mode: filled cells overwrite, blank cells leave fields untouched.",
    mode === "member"
      ? "Values must match this project: pick from the dropdowns, fed by the Reference sheet. Anything that does not match is rejected, not created. Every upload opens a review screen first; error rows are skipped and reported, and nothing is written until you apply."
      : "Every upload opens a review screen first: adds, updates with per-field diffs, and errors named by row and column; error rows are skipped on Apply and exportable as a report. Append adds rows, Sync updates by #code, Override replaces after a typed confirmation.",
  ];
}
// REV242: audit categorisation. AUDIT_CATS drives both the server-side category filter
// (ilike patterns: leading % means contains, otherwise starts-with) and the client-side
// classifier, so the pills and the chips can never disagree.
const AUDIT_CATS = [
  ["imp", "Imports & exports", ["import%", "export%", "send benchmarks%"]],
  ["wit", "Witnessing", ["%witness%", "%retest%"]],
  ["team", "Team & access", ["%member%", "%privilege%", "%request%", "%role%", "%invite resent%"]],
  ["act", "Activities", ["%activity%", "%activities%", "%constraint%", "%milestone%", "daily update%"]],
];
function auditCatOf(action) {
  const a = String(action || "").toLowerCase();
  const hit = (pats) => pats.some((pt) => { const core = pt.replace(/%/g, ""); return pt.charAt(0) === "%" ? a.includes(core) : a.startsWith(core); });
  for (const [k, , pats] of AUDIT_CATS) if (hit(pats)) return k;
  return "other";
}
function auditChipOf(action) {
  const a = String(action || "").toLowerCase();
  if (a.startsWith("daily update")) return { t: "UPDATE", c: "#2dd4bf" };
  if (a.startsWith("revert") || a.startsWith("restore")) return { t: "REVERT", c: "var(--st-warn)" };
  if (a.includes("witness") || a.includes("retest")) return { t: "WITNESS", c: "#b79bf0" };
  if (a.startsWith("import")) return { t: "IMPORT", c: "#a78bfa" };
  if (a.startsWith("export") || a.startsWith("send benchmarks")) return { t: "EXPORT", c: "#a78bfa" };
  if (a.startsWith("completed")) return { t: "DONE", c: "#2dd4bf" };
  if (a.startsWith("remove") || a.startsWith("delete")) return { t: "REMOVED", c: "#F87171" };
  if (a.startsWith("add") || a.startsWith("create") || a.startsWith("copy") || a.startsWith("acknowledge") || a.startsWith("clear")) return { t: "ADDED", c: "var(--st-ok)" };
  if (/^(edit|update|change|rename|move|resize|find|bulk|commit|start)/.test(a)) return { t: "EDITED", c: "#5B9BF3" };
  return { t: "OTHER", c: "#8593a2" };
}
function auditDayLabel(ts, now) {
  const d = new Date(ts); const n = now || new Date();
  const day = (x) => new Date(x.getFullYear(), x.getMonth(), x.getDate()).getTime();
  const diff = Math.round((day(n) - day(d)) / 86400000);
  if (diff === 0) return "Today";
  if (diff === 1) return "Yesterday";
  return d.toLocaleDateString("en-GB", { weekday: "short", day: "2-digit", month: "short" }) + (d.getFullYear() !== n.getFullYear() ? " " + d.getFullYear() : "");
}
function auditRelTime(ts, now) {
  const ms = (now ? now.getTime() : Date.now()) - new Date(ts).getTime();
  if (ms < 0 || ms > 6 * 86400000) return "";
  const m = Math.floor(ms / 60000);
  if (m < 1) return "just now";
  if (m < 60) return m + " min ago";
  const h = Math.floor(m / 60);
  if (h < 24) return h + " h ago";
  return Math.floor(h / 24) + " d ago";
}
// REV244: YTT card expansion. Percent editing follows the REV230 rule (canPct);
// daily updates are an append-only log (canNote = admins and the owner). ups is the
// fetched log for this activity: null while loading, { err } when the fetch failed.
function YttExpand({ a, ups, canPct, canNote, canCons, onAddCons, busy, onSave }) {
  const [ct, setCt] = useState("");
  const [co, setCo] = useState("");
  const [cd, setCd] = useState("");
  const [cBusy, setCBusy] = useState(false);
  const [pct, setPct] = useState(a.percent == null ? "" : String(a.percent));
  const [note, setNote] = useState("");
  const [err, setErr] = useState("");
  const pctN = pct === "" ? null : Math.max(0, Math.min(100, Math.round(+pct) || 0));
  const pctChanged = pctN != null && pctN !== (a.percent == null ? null : a.percent);
  const canSave = !busy && ((canNote && note.trim()) || (canPct && pctChanged));
  const lbl = { fontSize: 9, fontWeight: 800, letterSpacing: ".6px", textTransform: "uppercase", color: "var(--muted)", margin: "0 0 5px" };
  const when = (ts) => new Date(ts).toLocaleString("en-GB", { day: "2-digit", month: "short", hour: "2-digit", minute: "2-digit" });
  return (
    <div style={{ marginTop: 9, borderTop: "1px solid var(--line)", paddingTop: 9 }} onClick={(e) => e.stopPropagation()}>
      {canCons && <>
        <div style={lbl}>Add constraint</div>
        <div style={{ display: "flex", gap: 6 }}>
          <input className="lk-in" style={{ flex: 1, minWidth: 0 }} placeholder="What is blocking this activity?" value={ct} onChange={(e) => setCt(e.target.value)} />
          <input className="lk-in" style={{ width: 96 }} placeholder="Owner" value={co} onChange={(e) => setCo(e.target.value)} />
          <input className="lk-in" type="date" style={{ width: 130 }} value={cd} onChange={(e) => setCd(e.target.value)} />
          <button className="lk-btn primary" disabled={cBusy || !ct.trim()} onClick={async () => { setCBusy(true); setErr(""); try { await onAddCons({ text: ct.trim(), owner: co.trim(), due: cd }); setCt(""); setCo(""); setCd(""); } catch (e) { setErr(String((e && e.message) || e)); } finally { setCBusy(false); } }}>Add</button>
        </div>
        <div style={{ fontSize: 10.5, color: "var(--muted)", margin: "4px 0 10px" }}>Adds an open constraint to this activity and records it in the audit log.</div>
      </>}
      <div style={lbl}>Percent complete</div>
      {canPct
        ? <div style={{ display: "flex", gap: 12, alignItems: "center", marginBottom: 10 }}>
            <input type="range" min={0} max={100} value={pctN == null ? 0 : pctN} style={{ flex: 1, accentColor: "var(--accent)" }} onChange={(e) => setPct(e.target.value)} />
            <input className="lk-in" style={{ width: 62, textAlign: "center", fontWeight: 700 }} value={pct} placeholder="\u00b7" onChange={(e) => setPct(e.target.value.replace(/[^0-9]/g, "").slice(0, 3))} />
          </div>
        : <div style={{ fontSize: 12, color: "var(--muted)", marginBottom: 10 }}>{a.percent == null ? "Not recorded." : a.percent + "%"}</div>}
      <div style={lbl}>Daily updates</div>
      {ups == null && <div style={{ fontSize: 11.5, color: "var(--muted)" }}>Loading updates...</div>}
      {ups && ups.err && <div style={{ fontSize: 11.5, color: "var(--st-warn)", lineHeight: 1.5 }}>Daily updates are unavailable: {ups.err}. If this mentions a missing table, run the 2026-07-12_activity-updates migration in the Supabase SQL Editor.</div>}
      {ups && !ups.err && (ups.length === 0
        ? <div style={{ fontSize: 11.5, color: "var(--muted)" }}>No daily updates yet.</div>
        : <div style={{ display: "flex", flexDirection: "column", gap: 6, maxHeight: 180, overflowY: "auto" }}>
            {ups.map((u) => <div key={u.id} style={{ fontSize: 11.5, lineHeight: 1.5 }}>
              <span style={{ color: "var(--muted)", fontWeight: 700 }}>{when(u.at)} {"\u00b7"} {u.by_name || "admin"}{u.pct != null ? <span style={{ color: "var(--accent)", fontWeight: 800 }}> {"\u00b7"} {u.pct}%</span> : null}:</span> {u.note}
            </div>)}
          </div>)}
      {canNote
        ? <>
            <textarea className="lk-in" style={{ width: "100%", minHeight: 66, marginTop: 8, resize: "vertical", lineHeight: 1.5 }} placeholder="Today's update..." value={note} onChange={(e) => setNote(e.target.value)} />
            <div style={{ display: "flex", gap: 8, alignItems: "center", marginTop: 6 }}>
              <span style={{ fontSize: 10.5, color: "var(--muted)", flex: 1 }}>Appends a stamped entry; entries cannot be edited or removed.</span>
              <button className="lk-btn primary" disabled={!canSave} onClick={async () => { setErr(""); try { await onSave({ pct: canPct && pctChanged ? pctN : null, note: note.trim() }); setNote(""); } catch (e) { setErr(String((e && e.message) || e)); } }}>{busy ? "Saving..." : "Save update"}</button>
            </div>
          </>
        : <div style={{ fontSize: 10.5, color: "var(--muted)", marginTop: 8 }}>Daily updates can be added by admins and the owner.{canPct && pctChanged ? " Your percent change saves with the button below." : ""}{canPct ? <div style={{ marginTop: 6, textAlign: "right" }}><button className="lk-btn primary" disabled={!canSave} onClick={async () => { setErr(""); try { await onSave({ pct: pctChanged ? pctN : null, note: "" }); } catch (e) { setErr(String((e && e.message) || e)); } }}>{busy ? "Saving..." : "Save percent"}</button></div> : null}</div>}
      {err && <div style={{ fontSize: 11, color: "#F87171", fontWeight: 600, marginTop: 6 }}>{err}</div>}
    </div>
  );
}
function ImportStepsV2({ step }) {
  const steps = ["Template", "Mode", "Upload", "Review", "Apply"];
  return (
    <div style={{ display: "flex", alignItems: "center", margin: "4px 0 12px", flexWrap: "wrap", rowGap: 6 }}>
      {steps.map((lb, i) => { const n = i + 1; const on = n === step; const done = n < step; return (
        <React.Fragment key={lb}>
          {i > 0 && <div style={{ width: 20, height: 1, background: done || on ? "var(--accent)" : "var(--line)", margin: "0 7px" }} />}
          <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
            <div style={{ width: 20, height: 20, borderRadius: "50%", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 10, fontWeight: 800, background: on ? "var(--accent)" : done ? "rgba(91,155,243,.16)" : "transparent", color: on ? "#fff" : done ? "var(--accent)" : "var(--muted)", border: "1px solid " + (on || done ? "var(--accent)" : "var(--line)"), boxSizing: "border-box" }}>{done ? "\u2713" : n}</div>
            <div style={{ fontSize: 10.5, fontWeight: on ? 800 : 600, color: on ? "var(--ink, inherit)" : "var(--muted)", letterSpacing: ".2px" }}>{lb}</div>
          </div>
        </React.Fragment>
      ); })}
    </div>
  );
}

function ImportReviewPanel({ rows, notices, syncOn, applying, onApply, onCancel }) {
  const [filt, setFilt] = useState("all");
  const addN = rows.filter((r) => r.st === "add").length;
  const updN = rows.filter((r) => r.st === "upd").length;
  const sameN = rows.filter((r) => r.st === "same").length;
  const errN = rows.filter((r) => r.st === "err").length;
  const cleanN = addN + updN + sameN;
  const shown = rows.filter((r) => filt === "all" ? true : r.st === filt);
  const chip = (st) => { const c = st === "add" ? ["var(--st-ok)", "color-mix(in srgb, var(--st-ok) 14%, transparent)", "Add"] : st === "upd" ? ["var(--accent)", "rgba(91,155,243,.14)", "Update"] : st === "same" ? ["var(--muted)", "rgba(133,147,162,.14)", "No change"] : ["#F87171", "rgba(248,113,113,.14)", "Error"]; return <span style={{ fontSize: 9.5, fontWeight: 800, padding: "2px 8px", borderRadius: 6, color: c[0], background: c[1], whiteSpace: "nowrap" }}>{c[2]}</span>; };
  const pill = (key, label, n, red) => n === 0 && key !== "all" ? null : <button key={key} className="lk-btn" style={{ padding: "3px 10px", fontSize: 11, fontWeight: 700, borderColor: filt === key ? "var(--accent)" : undefined, color: red ? "#F87171" : undefined }} onClick={() => setFilt(key)}>{label} {n}</button>;
  const errReport = () => { const lines = ["Error"]; rows.filter((r) => r.st === "err").forEach((r) => { const t = (r.raw || r.detail || "").replace(/"/g, '""'); lines.push(/[",\n]/.test(t) ? '"' + t + '"' : t); }); downloadFile("import-errors.csv", lines.join("\n")); };
  const gcols = "52px 1.7fr 1fr 92px 2.5fr";
  return (
    <div>
      {!!(notices || []).length && <div style={{ fontSize: 12, color: "var(--st-warn)", margin: "0 0 8px", lineHeight: 1.5 }}>{notices.map((nn, i) => <div key={i}>{nn}</div>)}</div>}
      <div style={{ border: "1px solid var(--line)", borderRadius: 10, overflow: "hidden" }}>
        <div style={{ maxHeight: 320, overflowY: "auto", position: "relative" }}>
          <div style={{ position: "sticky", top: 0, zIndex: 5, background: "var(--card)" }}>
            <div style={{ display: "flex", gap: 6, alignItems: "center", padding: "9px 12px", borderBottom: "1px solid var(--line)", flexWrap: "wrap" }}>
              {pill("all", "All", rows.length)}{pill("add", "Adds", addN)}{pill("upd", "Updates", updN)}{pill("same", "No change", sameN)}{pill("err", "Errors", errN, true)}
              <span style={{ flex: 1 }} />
              {errN > 0 && <button className="lk-btn" style={{ padding: "3px 10px", fontSize: 11 }} onClick={errReport}>Error report (.csv)</button>}
            </div>
            <div style={{ display: "grid", gridTemplateColumns: gcols, gap: 10, padding: "7px 12px", fontSize: 9.5, fontWeight: 800, letterSpacing: ".5px", textTransform: "uppercase", color: "var(--muted)", borderBottom: "1px solid var(--line)" }}>
              <div>Row</div><div>Activity</div><div>Company</div><div>Result</div><div>Detail</div>
            </div>
          </div>
          {shown.map((r, i) => (
            <div key={i} style={{ display: "grid", gridTemplateColumns: gcols, gap: 10, alignItems: "start", padding: "7px 12px", fontSize: 11.5, borderBottom: "1px solid var(--line2, rgba(255,255,255,.05))" }}>
              <div style={{ color: "var(--muted)" }}>{r.ln || ""}</div>
              <div style={{ overflow: "hidden", textOverflow: "ellipsis" }}>{r.desc || (r.st === "err" ? <span style={{ color: "var(--muted)" }}>see detail</span> : "")}</div>
              <div style={{ color: "var(--muted)", overflow: "hidden", textOverflow: "ellipsis" }}>{r.co || ""}</div>
              <div>{chip(r.st)}</div>
              <div style={{ color: r.st === "err" ? "#F87171" : "var(--muted)", lineHeight: 1.45 }}>{r.detail}</div>
            </div>
          ))}
          {!shown.length && <div style={{ padding: 14, fontSize: 12, color: "var(--muted)" }}>Nothing under this filter.</div>}
        </div>
      </div>
      <div style={{ display: "flex", gap: 10, alignItems: "center", marginTop: 10 }}>
        <div style={{ fontSize: 11.5, color: "var(--muted)", flex: 1, lineHeight: 1.45 }}>
          {errN > 0
            ? `${errN} row${errN === 1 ? " has an error and will be skipped" : "s have errors and will be skipped"}. Fix and re-upload, or apply the clean rows and take the error report.`
            : "Nothing is written until you apply."}
          {syncOn ? " Sync: filled cells overwrite, blank cells leave fields untouched." : ""}
        </div>
        <button className="lk-btn" onClick={onCancel} disabled={applying}>Cancel</button>
        <button className="lk-btn primary" disabled={applying || cleanN === 0} onClick={onApply}>{applying ? "Applying" : `Apply ${cleanN} ${errN > 0 ? "clean " : ""}row${cleanN === 1 ? "" : "s"}`}</button>
      </div>
    </div>
  );
}

function ConstraintHistoryBody({ c, audit }) {
  const ev = c.hist || [];
  const fmt = (iso) => { try { return new Date(iso).toLocaleString("en-GB", { weekday: "short", day: "numeric", month: "short", year: "numeric", hour: "2-digit", minute: "2-digit" }); } catch (e) { return iso; } };
  // Event marks per the approved mockup: raised = hollow blue, cleared = filled green,
  // reopened = hollow amber, joined by a rail line; the last open event says "still open".
  const T = { raised: ["Raised", "#5B9BF3", false], cleared: ["Cleared", "var(--st-done)", true], reopened: ["Reopened", "var(--st-warn)", false] };
  if (ev.length) return <div style={{ margin: "4px 0 2px" }}>{ev.map((e, i) => {
    const m = T[e.t] || [e.t, "var(--muted)", false];
    const last = i === ev.length - 1;
    const still = last && !c.done && (e.t === "raised" || e.t === "reopened");
    return <div key={i} style={{ display: "grid", gridTemplateColumns: "14px 1fr", gap: 10, position: "relative", paddingBottom: last ? 0 : 14 }}>
      {!last && <span style={{ position: "absolute", left: 6, top: 15, bottom: 0, width: 1, background: "var(--line)" }} />}
      <span style={{ width: 13, height: 13, borderRadius: "50%", border: "2px solid " + m[1], background: m[2] ? m[1] : "var(--card)", marginTop: 2, boxSizing: "border-box" }} />
      <span style={{ minWidth: 0 }}><b style={{ fontSize: 12.5, display: "block", lineHeight: 1.35 }}>{m[0]} by {e.by || "unknown"}</b><span style={{ fontSize: 11, color: "var(--muted)" }}>{fmt(e.at)}{still ? " \u00b7 still open" : ""}</span></span>
    </div>; })}</div>;
  const rel = (audit || []).filter((x) => x.detail && c.text && String(x.detail).toLowerCase().includes(String(c.text).toLowerCase())).slice(0, 3);
  return <div style={{ fontSize: 11.5, color: "var(--muted)", lineHeight: 1.55 }}>This constraint predates history tracking, so no record exists on it.{rel.length ? <> Related audit entries:{rel.map((x, i) => <span key={i} style={{ display: "block", marginTop: 5 }}><b style={{ color: "var(--ink)" }}>{x.action}</b> by {x.user || "unknown"}, {fmt(x.ts)}</span>)}</> : " The audit trail shows no related entries."}</div>;
}
const openCount = (a) => a.constraints.filter((c) => !c.done).length;
const uid = (p) => (typeof crypto !== "undefined" && crypto.randomUUID ? crypto.randomUUID() : p + Date.now().toString(36) + Math.random().toString(36).slice(2, 5));
const nextCode = (acts) => (acts || []).reduce((m, a) => Math.max(m, a.code || 0), 0) + 1;
const SLIP_REASONS = ["Prerequisite work incomplete", "Materials / equipment", "Labour / resources", "Design / information / RFI", "Access / permit / approval", "Weather / environment", "Rework / quality / defect", "Changed priorities", "Safety", "Other"];
// Witness outcome (invitation-flagged activities only). Failure reasons are a quality taxonomy,
// deliberately separate from SLIP_REASONS which measure planning misses.
const WITNESS_FAIL_REASONS = ["Test failure / defect found", "Documentation incomplete (ITP / red-line)", "Witness no-show (client / CxA)", "Prerequisite system not available", "Test equipment fault", "Environmental / access constraint", "Other"];
const witnessOutcome = (a) => (a && a.witnessInvite ? (a.outcome || "pending") : "pending");
const isFailedInvite = (a) => witnessOutcome(a) === "failed";
const isPassedInvite = (a) => witnessOutcome(a) === "succeeded";
// Attempt number via the retest_of chain: original = 1, first retest = 2 (chip shows RETEST #1), and so on.
const attemptNo = (a, acts) => { let n = 1; const seen = new Set([a.id]); let cur = a; while (cur && cur.retestOf) { const p = (acts || []).find((x) => x.id === cur.retestOf); if (!p || seen.has(p.id)) break; seen.add(p.id); n++; cur = p; } return n; };
// REV254: the frozen in-bundle changelog fossil is gone. public/changelog.json is the
// single source; it is fetched once at module load into CHANGELOG_LIVE below, whose only
// consumer is the weekly report's changelog rows. Reports are user-triggered long after
// the same-origin fetch resolves, so an empty start is safe; if the fetch ever fails the
// report simply shows no changelog rows rather than months-stale ones.
// REV313: the deployed changelog head doubles as a build stamp for the digest skew guard.
// Cache-busted read; returns the latest rev string, or null on any failure (fail-open).
async function fetchDeployedRev() {
  try {
    const r = await fetch("/changelog.json?ts=" + Date.now(), { cache: "no-store" });
    if (!r || !r.ok) return null;
    const j = await r.json();
    return Array.isArray(j) && j.length ? ((j[0] && j[0].rev) || null) : null;
  } catch (e) { return null; }
}
let CHANGELOG_LIVE = [];
try { fetch("/changelog.json").then((r) => (r && r.ok ? r.json() : null)).then((j) => { if (Array.isArray(j) && j.length) CHANGELOG_LIVE = j; }).catch(() => {}); } catch (e) {}

const relTime = (iso) => { if (!iso) return ""; const d = new Date(iso); const s = Math.floor((Date.now() - d.getTime()) / 1000); if (s < 60) return "just now"; const m = Math.floor(s / 60); if (m < 60) return m + "m ago"; const h = Math.floor(m / 60); if (h < 24) return h + "h ago"; const dd = Math.floor(h / 24); if (dd < 30) return dd + "d ago"; return d.toLocaleDateString("en-GB", { day: "2-digit", month: "short", year: "numeric" }); };
const csvCell = (v) => { const s = v == null ? "" : String(v); return /[",\n]/.test(s) ? '"' + s.replace(/"/g, '""') + '"' : s; };
const toCSV = (headers, rows) => "\uFEFF" + [headers.join(","), ...rows.map((r) => r.map(csvCell).join(","))].join("\r\n");
const downloadFile = (name, text) => { try { const url = URL.createObjectURL(new Blob([text], { type: "text/csv" })); const a = document.createElement("a"); a.href = url; a.download = name; document.body.appendChild(a); a.click(); a.remove(); setTimeout(() => URL.revokeObjectURL(url), 1000); } catch (e) {} };
const SUBSEP = " \u203A "; // area › sub-area, used as the lane key when grouping by sub-area
const laneOfArea = (a) => a.area ? (a.subArea ? a.area + SUBSEP + a.subArea : a.area) : "Unassigned";

// The app's host for report footers and links, read from the running page.
const APP_HOST = (typeof window !== "undefined" && window.location && window.location.hostname) || "dlp-pi.vercel.app";
// One-time migration: browser preferences saved under the legacy fin04_ prefix carry
// over to the platform-neutral dlp_ prefix. Existing dlp_ values win; legacy keys stay put.
try { Object.keys(window.localStorage).forEach((k) => { if (k.indexOf("fin04_") === 0) { const nk = "dlp_" + k.slice(6); if (window.localStorage.getItem(nk) === null) window.localStorage.setItem(nk, window.localStorage.getItem(k)); } }); } catch (e) {}

