    const parts = [a.desc || "", locCode(a), a.witnessAt || "", a.witnessDurationMin || 60, a.accUrl || "", a.fokRef || "", (to || []).slice().sort(), (cc || []).slice().sort()];
    if (a.witnessType) parts.push(a.witnessType);
