  const cancelInvSafe = async (ol, id, comment) => { try { await ol.cancelWitnessEvent(id, comment); } catch (cerr) { if (!(cerr && (cerr.status === 404 || cerr.graphCode === "ErrorItemNotFound"))) throw cerr; } };
